// 各所見に独立した検証者を立て、多数決で採否
const votes = await parallel(
  ["correctness", "security", "repro"].map((lens) => () =>
    agent(`次の所見を${lens}の観点で反証せよ。確証がなければ refuted=true。`, { schema: VERDICT }))
);
const survives = votes.filter(Boolean).filter((v) => !v.refuted).length >= 2;

const seen = new Set();
let dry = 0;
while (dry < 2) {
  const fresh = (await findOnce()).filter((x) => !seen.has(key(x)));
  if (!fresh.length) { dry++; continue; }
  dry = 0;
  fresh.forEach((x) => seen.add(key(x)));
  // ...検証して採用
}

